// src/components/ParticlesBg.jsx
import { useEffect, useRef } from 'react';

export default function ParticlesBg({ opacity = 0.5 }) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;
    
    // Aumentamos el radio de interacción del ratón
    let mouse = { x: null, y: null, radius: 180 };

    const resize = () => {
      canvas.width  = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
    };
    resize();

    const ro = new ResizeObserver(resize);
    ro.observe(canvas.parentElement);

    // Aumentamos la cantidad para que la red sea más tupida
    const PARTICLE_COUNT = 85; 
    const CONNECTION_DIST = 140;

    const particles = Array.from({ length: PARTICLE_COUNT }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      vx: (Math.random() - 0.5) * 0.6,
      vy: (Math.random() - 0.5) * 0.6,
      baseR: Math.random() * 1.5 + 0.5,
      r: 0,
      angle: Math.random() * Math.PI * 2, // Para el movimiento ondulante
    }));

    const onMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      mouse.x = e.clientX - rect.left;
      mouse.y = e.clientY - rect.top;
    };
    const onLeave = () => { mouse.x = null; mouse.y = null; };
    
    canvas.addEventListener('mousemove', onMove);
    canvas.addEventListener('mouseleave', onLeave);

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach(p => {
        // Movimiento orgánico (flotación ondulante)
        p.angle += 0.015;
        p.x += p.vx + Math.cos(p.angle) * 0.3;
        p.y += p.vy + Math.sin(p.angle) * 0.3;

        // Interacción con el ratón: Campo de repulsión elástico
        let distToMouse = 9999;
        if (mouse.x !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          distToMouse = Math.sqrt(dx * dx + dy * dy);
          
          if (distToMouse < mouse.radius) {
            const force = (mouse.radius - distToMouse) / mouse.radius;
            // Empuja las partículas hacia afuera suavemente
            p.x -= (dx / distToMouse) * force * 2;
            p.y -= (dy / distToMouse) * force * 2;
          }
        }

        // Rebote en los bordes de la pantalla
        if (p.x < 0 || p.x > canvas.width)  p.vx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

        // Dibujar partícula con efecto "Glow" al pasar el ratón
        const isHovered = distToMouse < mouse.radius;
        p.r = p.baseR + (isHovered ? 1.5 : 0);
        
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        
        const alpha = isHovered ? opacity * 1.8 : opacity * 0.6;
        ctx.fillStyle = `rgba(232, 58, 58, ${alpha})`;
        
        // Efecto neón
        if (isHovered) {
          ctx.shadowBlur = 15;
          ctx.shadowColor = "rgba(232, 58, 58, 1)";
        } else {
          ctx.shadowBlur = 0;
        }
        
        ctx.fill();
        ctx.shadowBlur = 0; // Resetear sombra para las conexiones
      });

      // Dibujar conexiones (la red)
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < CONNECTION_DIST) {
            // Calcular si el centro de la línea está cerca del ratón
            let lineGlow = 0;
            if (mouse.x !== null) {
              const midX = (particles[i].x + particles[j].x) / 2;
              const midY = (particles[i].y + particles[j].y) / 2;
              const mdx = mouse.x - midX;
              const mdy = mouse.y - midY;
              const mDist = Math.sqrt(mdx * mdx + mdy * mdy);
              
              if (mDist < mouse.radius) {
                lineGlow = 1 - (mDist / mouse.radius);
              }
            }

            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);

            // Mezclar la opacidad base con el brillo del ratón
            const baseAlpha = 1 - dist / CONNECTION_DIST;
            const finalAlpha = (baseAlpha * 0.3 + lineGlow * 0.7) * opacity;

            ctx.strokeStyle = `rgba(232, 58, 58, ${finalAlpha})`;
            ctx.lineWidth = lineGlow > 0 ? 1.5 : 0.6;
            ctx.stroke();
          }
        }
      }

      animId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(animId);
      ro.disconnect();
      canvas.removeEventListener('mousemove', onMove);
      canvas.removeEventListener('mouseleave', onLeave);
    };
  }, [opacity]);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute',
        inset: 0,
        width: '100%',
        height: '100%',
        zIndex: 0,
        pointerEvents: 'auto',
      }}
    />
  );
}
